use std::collections::BTreeMap;
use std::f64::consts::PI;
use std::io::{self, Read};

pub const LT: &str = "LT";
pub const EQ: &str = "EQ";
pub const GT: &str = "GT";

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

#[derive(Debug, Clone)]
enum JVal {
    Obj(BTreeMap<String, JVal>),
    Arr(Vec<JVal>),
    Str(String),
    Num(f64),
    Bool(bool),
    Null,
}

struct Parser<'a> {
    s: &'a [u8],
    i: usize,
}

impl<'a> Parser<'a> {
    fn new(s: &'a str) -> Self {
        Self {
            s: s.as_bytes(),
            i: 0,
        }
    }

    fn parse(mut self) -> Result<JVal, String> {
        let v = self.parse_val()?;
        self.skip_ws();
        if self.i != self.s.len() {
            return Err("trailing characters".to_string());
        }
        Ok(v)
    }

    fn skip_ws(&mut self) {
        while self.i < self.s.len() && matches!(self.s[self.i], b' ' | b'\n' | b'\r' | b'\t') {
            self.i += 1;
        }
    }

    fn peek(&self) -> Option<u8> {
        self.s.get(self.i).copied()
    }

    fn take(&mut self) -> Option<u8> {
        let c = self.peek()?;
        self.i += 1;
        Some(c)
    }

    fn expect(&mut self, c: u8) -> Result<(), String> {
        match self.take() {
            Some(got) if got == c => Ok(()),
            _ => Err(format!("expected '{}'", c as char)),
        }
    }

    fn parse_val(&mut self) -> Result<JVal, String> {
        self.skip_ws();
        match self.peek() {
            Some(b'{') => self.parse_obj(),
            Some(b'[') => self.parse_arr(),
            Some(b'"') => Ok(JVal::Str(self.parse_str()?)),
            Some(b't') => {
                self.expect_bytes(b"true")?;
                Ok(JVal::Bool(true))
            }
            Some(b'f') => {
                self.expect_bytes(b"false")?;
                Ok(JVal::Bool(false))
            }
            Some(b'n') => {
                self.expect_bytes(b"null")?;
                Ok(JVal::Null)
            }
            Some(b'-' | b'0'..=b'9') => Ok(JVal::Num(self.parse_num()?)),
            _ => Err("invalid JSON value".to_string()),
        }
    }

    fn expect_bytes(&mut self, bs: &[u8]) -> Result<(), String> {
        if self.i + bs.len() > self.s.len() {
            return Err("unexpected eof".to_string());
        }
        if &self.s[self.i..self.i + bs.len()] == bs {
            self.i += bs.len();
            Ok(())
        } else {
            Err("token mismatch".to_string())
        }
    }

    fn parse_obj(&mut self) -> Result<JVal, String> {
        self.expect(b'{')?;
        self.skip_ws();
        let mut map = BTreeMap::new();
        if self.peek() == Some(b'}') {
            self.i += 1;
            return Ok(JVal::Obj(map));
        }
        loop {
            self.skip_ws();
            let k = self.parse_str()?;
            self.skip_ws();
            self.expect(b':')?;
            let v = self.parse_val()?;
            map.insert(k, v);
            self.skip_ws();
            match self.take() {
                Some(b',') => continue,
                Some(b'}') => break,
                _ => return Err("expected ',' or '}'".to_string()),
            }
        }
        Ok(JVal::Obj(map))
    }

    fn parse_arr(&mut self) -> Result<JVal, String> {
        self.expect(b'[')?;
        self.skip_ws();
        let mut arr = Vec::new();
        if self.peek() == Some(b']') {
            self.i += 1;
            return Ok(JVal::Arr(arr));
        }
        loop {
            arr.push(self.parse_val()?);
            self.skip_ws();
            match self.take() {
                Some(b',') => continue,
                Some(b']') => break,
                _ => return Err("expected ',' or ']'".to_string()),
            }
        }
        Ok(JVal::Arr(arr))
    }

    fn parse_str(&mut self) -> Result<String, String> {
        self.expect(b'"')?;
        let mut out = String::new();
        loop {
            let c = self.take().ok_or_else(|| "unterminated string".to_string())?;
            match c {
                b'"' => break,
                b'\\' => {
                    let esc = self.take().ok_or_else(|| "bad escape".to_string())?;
                    match esc {
                        b'"' => out.push('"'),
                        b'\\' => out.push('\\'),
                        b'/' => out.push('/'),
                        b'b' => out.push('\u{0008}'),
                        b'f' => out.push('\u{000C}'),
                        b'n' => out.push('\n'),
                        b'r' => out.push('\r'),
                        b't' => out.push('\t'),
                        b'u' => {
                            let code = self.parse_hex4()?;
                            if let Some(ch) = char::from_u32(code) {
                                out.push(ch);
                            } else {
                                return Err("invalid unicode escape".to_string());
                            }
                        }
                        _ => return Err("invalid escape".to_string()),
                    }
                }
                _ => out.push(c as char),
            }
        }
        Ok(out)
    }

    fn parse_hex4(&mut self) -> Result<u32, String> {
        let mut v: u32 = 0;
        for _ in 0..4 {
            let c = self.take().ok_or_else(|| "bad unicode escape".to_string())?;
            v = (v << 4)
                + match c {
                    b'0'..=b'9' => (c - b'0') as u32,
                    b'a'..=b'f' => (c - b'a' + 10) as u32,
                    b'A'..=b'F' => (c - b'A' + 10) as u32,
                    _ => return Err("bad unicode hex".to_string()),
                };
        }
        Ok(v)
    }

    fn parse_num(&mut self) -> Result<f64, String> {
        let start = self.i;
        if self.peek() == Some(b'-') {
            self.i += 1;
        }
        match self.peek() {
            Some(b'0') => self.i += 1,
            Some(b'1'..=b'9') => {
                self.i += 1;
                while matches!(self.peek(), Some(b'0'..=b'9')) {
                    self.i += 1;
                }
            }
            _ => return Err("bad number".to_string()),
        }
        if self.peek() == Some(b'.') {
            self.i += 1;
            let mut had_digit = false;
            while matches!(self.peek(), Some(b'0'..=b'9')) {
                self.i += 1;
                had_digit = true;
            }
            if !had_digit {
                return Err("bad fractional part".to_string());
            }
        }
        if matches!(self.peek(), Some(b'e' | b'E')) {
            self.i += 1;
            if matches!(self.peek(), Some(b'+' | b'-')) {
                self.i += 1;
            }
            let mut had_digit = false;
            while matches!(self.peek(), Some(b'0'..=b'9')) {
                self.i += 1;
                had_digit = true;
            }
            if !had_digit {
                return Err("bad exponent".to_string());
            }
        }
        std::str::from_utf8(&self.s[start..self.i])
            .map_err(|_| "bad utf8 number".to_string())?
            .parse::<f64>()
            .map_err(|_| "bad float".to_string())
    }
}

fn obj_get<'a>(obj: &'a BTreeMap<String, JVal>, k: &str) -> Result<&'a JVal, String> {
    obj.get(k).ok_or_else(|| format!("missing key {k}"))
}

fn as_obj(v: &JVal) -> Result<&BTreeMap<String, JVal>, String> {
    match v {
        JVal::Obj(o) => Ok(o),
        _ => Err("expected object".to_string()),
    }
}

fn as_arr(v: &JVal) -> Result<&Vec<JVal>, String> {
    match v {
        JVal::Arr(a) => Ok(a),
        _ => Err("expected array".to_string()),
    }
}

fn as_str(v: &JVal) -> Result<&str, String> {
    match v {
        JVal::Str(s) => Ok(s),
        _ => Err("expected string".to_string()),
    }
}

fn as_num(v: &JVal) -> Result<f64, String> {
    match v {
        JVal::Num(n) => Ok(*n),
        _ => Err("expected number".to_string()),
    }
}

fn as_bool(v: &JVal) -> Result<bool, String> {
    match v {
        JVal::Bool(b) => Ok(*b),
        _ => Err("expected bool".to_string()),
    }
}

#[derive(Clone, Debug)]
struct Parameters {
    length1: f64,
    radius1: f64,
    epsilon: f64,
    area1: f64,
    q_pts: usize,
    quads: usize,
    dist: f64,
    n_pts: usize,
    k_pts: usize,
    a_pts: usize,
    b_pts: usize,
    c_pts: usize,
    d_pts: usize,
    e_pts: usize,
    f_pts: usize,
    g_pts: usize,
    length2: f64,
    radius2: f64,
    area2: f64,
}

#[derive(Clone, Debug)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: Vec<Vec<String>>,
    pum_diag: Vec<bool>,
}

fn parse_input(s: &str) -> Result<Input, String> {
    let root = Parser::new(s).parse()?;
    let o = as_obj(&root)?;

    let numpoints = as_num(obj_get(o, "numpoints")?)? as usize;

    let x = as_arr(obj_get(o, "x")?)?
        .iter()
        .map(as_num)
        .collect::<Result<Vec<_>, _>>()?;
    let y = as_arr(obj_get(o, "y")?)?
        .iter()
        .map(as_num)
        .collect::<Result<Vec<_>, _>>()?;

    let po = as_obj(obj_get(o, "parameters")?)?;
    let p = Parameters {
        length1: as_num(obj_get(po, "LENGTH1")?)?,
        radius1: as_num(obj_get(po, "RADIUS1")?)?,
        epsilon: as_num(obj_get(po, "EPSILON")?)?,
        area1: as_num(obj_get(po, "AREA1")?)?,
        q_pts: as_num(obj_get(po, "Q_PTS")?)? as usize,
        quads: as_num(obj_get(po, "QUADS")?)? as usize,
        dist: as_num(obj_get(po, "DIST")?)?,
        n_pts: as_num(obj_get(po, "N_PTS")?)? as usize,
        k_pts: as_num(obj_get(po, "K_PTS")?)? as usize,
        a_pts: as_num(obj_get(po, "A_PTS")?)? as usize,
        b_pts: as_num(obj_get(po, "B_PTS")?)? as usize,
        c_pts: as_num(obj_get(po, "C_PTS")?)? as usize,
        d_pts: as_num(obj_get(po, "D_PTS")?)? as usize,
        e_pts: as_num(obj_get(po, "E_PTS")?)? as usize,
        f_pts: as_num(obj_get(po, "F_PTS")?)? as usize,
        g_pts: as_num(obj_get(po, "G_PTS")?)? as usize,
        length2: as_num(obj_get(po, "LENGTH2")?)?,
        radius2: as_num(obj_get(po, "RADIUS2")?)?,
        area2: as_num(obj_get(po, "AREA2")?)?,
    };

    let lcm = as_arr(obj_get(o, "lcm")?)?
        .iter()
        .map(|row| {
            as_arr(row)?
                .iter()
                .map(as_str)
                .map(|s| s.map(ToString::to_string))
                .collect::<Result<Vec<_>, _>>()
        })
        .collect::<Result<Vec<_>, _>>()?;

    let pum_diag = as_arr(obj_get(o, "pum_diag")?)?
        .iter()
        .map(as_bool)
        .collect::<Result<Vec<_>, _>>()?;

    Ok(Input {
        numpoints,
        x,
        y,
        parameters: p,
        lcm,
        pum_diag,
    })
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1)).sqrt()
}

fn points_equal(x1: f64, y1: f64, x2: f64, y2: f64) -> bool {
    realcompare(x1, x2) == EQ && realcompare(y1, y2) == EQ
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()) / 2.0
}

fn angle_condition(x1: f64, y1: f64, xv: f64, yv: f64, x3: f64, y3: f64, eps: f64) -> bool {
    if points_equal(x1, y1, xv, yv) || points_equal(x3, y3, xv, yv) {
        return false;
    }
    let v1x = x1 - xv;
    let v1y = y1 - yv;
    let v2x = x3 - xv;
    let v2y = y3 - yv;
    let n1 = (v1x * v1x + v1y * v1y).sqrt();
    let n2 = (v2x * v2x + v2y * v2y).sqrt();
    let mut c = (v1x * v2x + v1y * v2y) / (n1 * n2);
    c = c.clamp(-1.0, 1.0);
    let ang = c.acos();
    realcompare(ang, PI - eps) == LT || realcompare(ang, PI + eps) == GT
}

fn min_circle_radius_for_three(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    let a = dist(x2, y2, x3, y3);
    let b = dist(x1, y1, x3, y3);
    let c = dist(x1, y1, x2, y2);

    let mut s = [a, b, c];
    s.sort_by(|u, v| u.partial_cmp(v).unwrap());
    let s1 = s[0];
    let s2 = s[1];
    let s3 = s[2];

    if realcompare(s3 * s3, s1 * s1 + s2 * s2) != LT {
        return s3 / 2.0;
    }

    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if realcompare(area, 0.0) == EQ {
        return s3 / 2.0;
    }
    (a * b * c) / (4.0 * area)
}

fn quadrant(x: f64, y: f64) -> usize {
    let xcmp = realcompare(x, 0.0);
    let ycmp = realcompare(y, 0.0);
    if (xcmp == GT || xcmp == EQ) && (ycmp == GT || ycmp == EQ) {
        1
    } else if xcmp == LT && (ycmp == GT || ycmp == EQ) {
        2
    } else if (xcmp == LT || xcmp == EQ) && ycmp == LT {
        3
    } else {
        4
    }
}

fn dist_point_to_line(px: f64, py: f64, ax: f64, ay: f64, bx: f64, by: f64) -> f64 {
    let num = ((bx - ax) * (ay - py) - (ax - px) * (by - ay)).abs();
    let den = dist(ax, ay, bx, by);
    num / den
}

fn lic_cmv(input: &Input) -> Vec<bool> {
    let n = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let p = &input.parameters;

    let mut cmv = vec![false; 15];

    for i in 0..n.saturating_sub(1) {
        if realcompare(dist(x[i], y[i], x[i + 1], y[i + 1]), p.length1) == GT {
            cmv[0] = true;
            break;
        }
    }

    for i in 0..n.saturating_sub(2) {
        let rmin = min_circle_radius_for_three(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
        if realcompare(rmin, p.radius1) == GT {
            cmv[1] = true;
            break;
        }
    }

    for i in 0..n.saturating_sub(2) {
        if angle_condition(
            x[i],
            y[i],
            x[i + 1],
            y[i + 1],
            x[i + 2],
            y[i + 2],
            p.epsilon,
        ) {
            cmv[2] = true;
            break;
        }
    }

    for i in 0..n.saturating_sub(2) {
        if realcompare(
            triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]),
            p.area1,
        ) == GT
        {
            cmv[3] = true;
            break;
        }
    }

    if p.q_pts <= n {
        for i in 0..=n - p.q_pts {
            let mut used = [false; 4];
            let mut count = 0;
            for j in i..i + p.q_pts {
                let q = quadrant(x[j], y[j]) - 1;
                if !used[q] {
                    used[q] = true;
                    count += 1;
                }
            }
            if realcompare(count as f64, p.quads as f64) == GT {
                cmv[4] = true;
                break;
            }
        }
    }

    for i in 0..n.saturating_sub(1) {
        if realcompare(x[i + 1] - x[i], 0.0) == LT {
            cmv[5] = true;
            break;
        }
    }

    if n >= 3 {
        for i in 0..=n - p.n_pts {
            let first = i;
            let last = i + p.n_pts - 1;
            if points_equal(x[first], y[first], x[last], y[last]) {
                let mut ok = false;
                for j in first..=last {
                    if realcompare(dist(x[j], y[j], x[first], y[first]), p.dist) == GT {
                        ok = true;
                        break;
                    }
                }
                if ok {
                    cmv[6] = true;
                    break;
                }
            } else {
                let mut ok = false;
                for j in first..=last {
                    if realcompare(
                        dist_point_to_line(
                            x[j], y[j], x[first], y[first], x[last], y[last],
                        ),
                        p.dist,
                    ) == GT
                    {
                        ok = true;
                        break;
                    }
                }
                if ok {
                    cmv[6] = true;
                    break;
                }
            }
        }
    }

    if n >= 3 {
        let step = p.k_pts + 1;
        for i in 0..n - step {
            if realcompare(dist(x[i], y[i], x[i + step], y[i + step]), p.length1) == GT {
                cmv[7] = true;
                break;
            }
        }
    }

    if n >= 5 {
        let jgap = p.a_pts + 1;
        let kgap = p.b_pts + 1;
        for i in 0..n {
            let j = i + jgap;
            let k = j + kgap;
            if k >= n {
                break;
            }
            let rmin = min_circle_radius_for_three(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(rmin, p.radius1) == GT {
                cmv[8] = true;
                break;
            }
        }
    }

    if n >= 5 {
        let jgap = p.c_pts + 1;
        let kgap = p.d_pts + 1;
        for i in 0..n {
            let j = i + jgap;
            let k = j + kgap;
            if k >= n {
                break;
            }
            if angle_condition(x[i], y[i], x[j], y[j], x[k], y[k], p.epsilon) {
                cmv[9] = true;
                break;
            }
        }
    }

    if n >= 5 {
        let jgap = p.e_pts + 1;
        let kgap = p.f_pts + 1;
        for i in 0..n {
            let j = i + jgap;
            let k = j + kgap;
            if k >= n {
                break;
            }
            if realcompare(triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]), p.area1) == GT {
                cmv[10] = true;
                break;
            }
        }
    }

    if n >= 3 {
        let step = p.g_pts + 1;
        for i in 0..n - step {
            if realcompare(x[i + step] - x[i], 0.0) == LT {
                cmv[11] = true;
                break;
            }
        }
    }

    if n >= 3 {
        let step = p.k_pts + 1;
        let mut gt_len1 = false;
        let mut lt_len2 = false;
        for i in 0..n - step {
            let d = dist(x[i], y[i], x[i + step], y[i + step]);
            if realcompare(d, p.length1) == GT {
                gt_len1 = true;
            }
            if realcompare(d, p.length2) == LT {
                lt_len2 = true;
            }
            if gt_len1 && lt_len2 {
                cmv[12] = true;
                break;
            }
        }
    }

    if n >= 5 {
        let jgap = p.a_pts + 1;
        let kgap = p.b_pts + 1;
        let mut gt_r1 = false;
        let mut le_r2 = false;
        for i in 0..n {
            let j = i + jgap;
            let k = j + kgap;
            if k >= n {
                break;
            }
            let rmin = min_circle_radius_for_three(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(rmin, p.radius1) == GT {
                gt_r1 = true;
            }
            if realcompare(rmin, p.radius2) != GT {
                le_r2 = true;
            }
            if gt_r1 && le_r2 {
                cmv[13] = true;
                break;
            }
        }
    }

    if n >= 5 {
        let jgap = p.e_pts + 1;
        let kgap = p.f_pts + 1;
        let mut gt_a1 = false;
        let mut lt_a2 = false;
        for i in 0..n {
            let j = i + jgap;
            let k = j + kgap;
            if k >= n {
                break;
            }
            let area = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
            if realcompare(area, p.area1) == GT {
                gt_a1 = true;
            }
            if realcompare(area, p.area2) == LT {
                lt_a2 = true;
            }
            if gt_a1 && lt_a2 {
                cmv[14] = true;
                break;
            }
        }
    }

    cmv
}

fn decide(input: &Input) -> (Vec<bool>, Vec<Vec<bool>>, Vec<bool>, bool) {
    let cmv = lic_cmv(input);

    let mut pum = vec![vec![true; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
    }
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            pum[i][j] = match input.lcm[i][j].as_str() {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => false,
            };
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&b| b);
        }
    }

    let launch = fuv.iter().all(|&b| b);
    (cmv, pum, fuv, launch)
}

fn bool_to_json(b: bool) -> &'static str {
    if b {
        "true"
    } else {
        "false"
    }
}

fn output_json(cmv: &[bool], pum: &[Vec<bool>], fuv: &[bool], launch: bool) -> String {
    let mut s = String::new();
    s.push('{');

    s.push_str("\"cmv\":[");
    for (i, b) in cmv.iter().enumerate() {
        if i > 0 {
            s.push(',');
        }
        s.push_str(bool_to_json(*b));
    }
    s.push(']');

    s.push_str(",\"pum\":[");
    for (i, row) in pum.iter().enumerate() {
        if i > 0 {
            s.push(',');
        }
        s.push('[');
        for (j, b) in row.iter().enumerate() {
            if j > 0 {
                s.push(',');
            }
            s.push_str(bool_to_json(*b));
        }
        s.push(']');
    }
    s.push(']');

    s.push_str(",\"fuv\":[");
    for (i, b) in fuv.iter().enumerate() {
        if i > 0 {
            s.push(',');
        }
        s.push_str(bool_to_json(*b));
    }
    s.push(']');

    s.push_str(",\"launch\":");
    s.push_str(bool_to_json(launch));

    s.push('}');
    s
}

fn main() {
    let mut input = String::new();
    if io::stdin().read_to_string(&mut input).is_err() {
        return;
    }

    let parsed = match parse_input(&input) {
        Ok(v) => v,
        Err(_) => return,
    };

    let (cmv, pum, fuv, launch) = decide(&parsed);
    let out = output_json(&cmv, &pum, &fuv, launch);
    println!("{out}");
}
